import React from 'react';
import './styles.css';

const items = [
  { id: 1, title: 'Mountain Vista', height: '12rem', color: '#93c5fd' },
  { id: 2, title: 'Ocean Breeze', height: '8rem', color: '#6ee7b7' },
  { id: 3, title: 'Desert Sunset', height: '16rem', color: '#fca5a5' },
  { id: 4, title: 'Forest Path', height: '10rem', color: '#a5b4fc' },
  { id: 5, title: 'City Lights', height: '14rem', color: '#fcd34d' },
  { id: 6, title: 'Arctic Ice', height: '9rem', color: '#a7f3d0' },
  { id: 7, title: 'Coral Reef', height: '11rem', color: '#f9a8d4' },
  { id: 8, title: 'Lava Flow', height: '7rem', color: '#fdba74' },
  { id: 9, title: 'Northern Lights', height: '13rem', color: '#c4b5fd' },
];

export default function App() {
  return (
    <div className="masonry" data-testid="masonry">
      {items.map(item => (
        <div key={item.id} className="masonry__item" data-testid={`item-${item.id}`}>
          <div
            className="masonry__image"
            style={{ height: item.height, backgroundColor: item.color }}
          />
          <h3 className="masonry__title">{item.title}</h3>
          <p className="masonry__desc">A beautiful photograph capturing nature's wonder.</p>
        </div>
      ))}
    </div>
  );
}

